```go
package main

import (
	"fmt"
	"net/http"
)

func handler(w http.ResponseWriter, r *http.Request) {
	// Read the request body into a string
	reqBody, err := ioutil.ReadAll(r.Body)
	if err != nil {
		fmt.Fprintf(w, "Error reading request body: %s", err)
		return
	}
	defer r.Body.Close()

	// Convert the byte slice to a string
	reqBodyStr := string(reqBody)

	// Print the request body
	fmt.Fprintf(w, "Request Content: %s", reqBodyStr)
}

func main() {
	http.HandleFunc("/", handler)
	fmt.Println("Server is running on :8080")
	http.ListenAndServe(":8080", nil)
}
```

### Explanation:
- **ioutil.ReadAll(r.Body)**: This reads the entire request body into a byte slice.
- **r.Body.Close()**: It's important to close the request body to free up resources.
- **fmt.Fprintf(w, "Request Content: %s", reqBodyStr)**: This writes the request content to the response.

This program sets up an HTTP server that listens on port 8080. When it receives a request, it reads and prints the content of the request body.

