In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions, along with file descriptor redirection. Here's a simple example:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <stdio.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid < 0) {  // Error
        perror("fork");
        return 1;
    } else if (pid == 0) {  // Child process
        // Close the write end of the pipe
        close(pipefd[1]);

        // Redirection: file descriptor 0 (stdin) to the read end of the pipe
        dup2(pipefd[0], STDIN_FILENO);

        // Close the pipe read end
        close(pipefd[0]);

        // Execute a command
        execlp("cat", "cat", (char*)0);
        perror("execlp");
        _exit(1);  // Exit, in case execlp() fails
    } else {  // Parent process
        // Close the read end of the pipe
        close(pipefd[0]);

        // Redirection: file descriptor 1 (stdout) to the write end of the pipe
        dup2(pipefd[1], STDOUT_FILENO);

        // Close the pipe write end
        close(pipefd[1]);

        // Wait for the child to finish
        wait(NULL);

        // Parent can now read from the pipe
        char buffer[100];
        read(pipefd[0], buffer, sizeof(buffer));
        std::cout << "Child output: " << buffer << std::endl;

        // Clean up
        close(pipefd[0]);
    }

    return 0;
}
```

This code creates a pipe, forges a child process, and redirects the child's stdin to the read end of the pipe. The parent process then redirects stdout to the write end of the pipe. The child process runs the `cat` command, and the parent reads the output from the pipe.
